import React, { useState } from "react";
import Navbar from '../../frontend/auth/Navbar';
import axios from "axios";
import Swal from "sweetalert2";

function Login()
{
    const [loginInput, setLogin] = useState({
        email: "",
        password: "",
        error_list: {},
    });

    const [loading, setLoading] = useState(false);

    const handleInput = (e) =>
    {
        e.persist();
        setLogin({
            ...loginInput,
            [e.target.name]: e.target.value,
        });
    }

    const loginSubmit = async (e) =>
    {
        e.preventDefault();
        setLoading(true);

        const data = {
            email: loginInput.email,
            password: loginInput.password,
        };

        Swal.fire({
            title: 'Logging In...',
            text: 'Please wait.',
            icon: 'info',
            allowOutsideClick: false,
            showConfirmButton: false,
            willOpen: () =>
            {
                Swal.showLoading();
            },
        });

        try
        {
            await axios.get('/sanctum/csrf-cookie');
            const response = await axios.post('/api/login', data);

            if (response.data.status === 200)
            {
                localStorage.setItem('auth_token', response.data.token);
                localStorage.setItem('auth_name', response.data.username);

                Swal.fire({
                    title: 'Login Successful!',
                    text: response.data.message,
                    icon: 'success',
                    timer: 2000,
                    showConfirmButton: false,
                });

                window.location.href = '/admin/dashboard';
            } else if (response.data.status === 401)
            {
                Swal.fire({
                    title: 'Login Failed',
                    text: response.data.message,
                    icon: 'error',
                });
            }
        } catch (error)
        {
            if (error.response)
            {
                if (error.response.status === 422)
                {
                    setLogin({ ...loginInput, error_list: error.response.data.validation_errors || {} });
                    Swal.close(); // Close the loading Swal
                } else if (error.response.status === 401)
                {
                    Swal.fire({
                        title: 'Login Failed',
                        text: error.response.data.message || 'Invalid Credentials.',
                        icon: 'error',
                    });
                } else
                {
                    Swal.fire({
                        title: 'Error',
                        text: 'Something went wrong. Please try again.',
                        icon: 'error',
                    });
                }
            } else
            {
                Swal.fire({
                    title: 'Connection Error',
                    text: 'Could not connect to the server.',
                    icon: 'warning',
                });
            }
        } finally
        {
            setLoading(false);
            if (Swal.isLoading())
            {
                Swal.close();
            }
        }
    }

    return (
        <div>
            <Navbar />
            <div className="container py-5">
                <div className="row justify-content-center">
                    <div className="col-xl-6">
                        <div className="card shadow">
                            <div className="card-header">
                                <h4 className="mb-0">Login</h4>
                            </div>
                            <div className="card-body">
                                <form onSubmit={loginSubmit}>
                                    <div className="form-group mb-3">
                                        <label htmlFor="email" className="form-label">Email</label>
                                        <input
                                            type="email"
                                            name="email"
                                            onChange={handleInput}
                                            value={loginInput.email}
                                            className={`form-control ${loginInput.error_list.email ? 'is-invalid' : ''}`}
                                            required
                                        />
                                        {loginInput.error_list.email && (
                                            <span className="text-danger">{loginInput.error_list.email[0]}</span>
                                        )}
                                    </div>

                                    <div className="form-group mb-3">
                                        <label htmlFor="password" className="form-label">Password</label>
                                        <input
                                            type="password"
                                            name="password"
                                            onChange={handleInput}
                                            value={loginInput.password}
                                            className={`form-control ${loginInput.error_list.password ? 'is-invalid' : ''}`}
                                            required
                                        />
                                        {loginInput.error_list.password && (
                                            <span className="text-danger">{loginInput.error_list.password[0]}</span>
                                        )}
                                    </div>

                                    <div className="form-group mb-3">
                                        <button type="submit" className="btn btn-primary" disabled={loading}>
                                            {loading ? 'Logging In...' : 'Login'}
                                        </button>
                                    </div>
                                </form>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}

export default Login;
